// Parse CalDAV XML response with all properties
const xml = $input.first().json.data || '';

const tasks = [];

// Match VTODO blocks
const vtodoMatches = xml.match(/<cal:VTODO[^>]*>[\s\S]*?<\/cal:VTODO>/gi) || [];

for (const vtodo of vtodoMatches) {
  // Helper to extract value
  const extract = (tag) => {
    const match = vtodo.match(new RegExp(`<cal:${tag}[^>]*>([^<]*)<\\/${tag}>`, 'i'));
    return match ? match[1] : null;
  };

  // Extract all properties
  const uid = extract('UID');
  const summary = extract('SUMMARY');
  const description = extract('DESCRIPTION');
  const status = extract('STATUS');
  const due = extract('DTEND');
  const dtstart = extract('DTSTART');
  const completed = extract('COMPLETED');
  const priority = extract('PRIORITY');
  const percentComplete = extract('PERCENT-COMPLETE');
  const categories = extract('CATEGORIES');
  const duration = extract('DURATION');
  const url = extract('URL');
  const location = extract('LOCATION');

  // Extract RELATED-TO
  const relatedToMatch = vtodo.match(/<cal:RELATED-TO[^>]*>([^<]*)<\/cal:RELATED-TO>/i);
  const parentTaskUid = relatedToMatch ? relatedToMatch[1] : null;

  // Extract RRULE
  const rruleMatch = vtodo.match(/<cal:RRULE[^>]*>([^<]*)<\/cal:RRULE>/i);
  const recurrence = rruleMatch ? rruleMatch[1] : null;

  // Extract href for task ID
  const hrefMatch = vtodo.match(/<d:href>([^<]*)<\/d:href>/i);
  const href = hrefMatch ? hrefMatch[1] : null;

  tasks.push({
    uid: uid || 'unknown',
    title: summary || 'Untitled',
    description: description || null,
    status: status || 'NEEDS-ACTION',
    due: due || null,
    startDate: dtstart || null,
    completed: completed || null,
    priority: priority ? parseInt(priority) : null,
    percentComplete: percentComplete ? parseInt(percentComplete) : null,
    categories: categories ? categories.split(',').map(c => c.trim()) : [],
    parentTaskUid: parentTaskUid || null,
    duration: duration || null,
    recurrence: recurrence || null,
    url: url || null,
    location: location || null,
    href: href || null
  });
}

return [{ json: { tasks, count: tasks.length } }];
